def calculate_vc_dimension(hypothesis_class, points):
 # Check if hypothesis class can shatter points
 for labeling in generate_labelings(points):
 if not any(can_classify(h, points, labeling) for h in hypothesis_class):
 return len(points) - 1
 return len(points)

def generate_labelings(points):
 # Generate all possible labelings of points
 labelings = []
 for i in range(2 ** len(points)):
 labeling = [bool((i >> j) & 1) for j in range(len(points))]
 labelings.append(labeling)
 return labelings

def can_classify(hypothesis, points, labeling):
 # Check if hypothesis can classify points according to labeling
 return all(hypothesis(point) == label for point, label in zip(points, labeling))

