int calculate_sample_complexity(double epsilon, double delta, int hypothesis_space_size) {
 // Calculate sample complexity using PAC learning bound
 int sample_complexity = ceil((1 / epsilon) * (log(hypothesis_space_size) + log(1 / delta)));
 return sample_complexity;
